import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;

public class TestMoreImages {
    public static void main(String[] args) {
        // Test that regular image tags still get converted outside SVG
        String h1 = "<body><image src='test.jpg'/></body>";
        Document doc1 = Jsoup.parse(h1);
        System.out.println("Regular image conversion: " + doc1.body().html());

        // Test nested SVG case
        String h2 = "<body><svg><image href='test.svg'/></svg><image src='test.jpg'/></body>";
        Document doc2 = Jsoup.parse(h2);
        System.out.println("Mixed case: " + doc2.body().html());

        // Test multiple nested SVGs
        String h3 = "<body><svg><svg><image /></svg></svg></body>";
        Document doc3 = Jsoup.parse(h3);
        System.out.println("Nested SVGs: " + doc3.body().html());
    }
}

